import java.util.*; public class Obra { private String titulo,categoria; private List<Autor> autores=new ArrayList<>(); public Obra(String titulo,String categoria){ this.titulo=titulo; this.categoria=categoria; } public void adicionarAutor(Autor autor){ autores.add(autor); } public String getTitulo(){ return titulo; } public void exibirDados(){ System.out.println("Obra: "+titulo+" ("+categoria+")"); for(Autor a:autores) System.out.println("Autor: "+a.getNome()+" - "+a.getNacionalidade()); } }
